import requests
import sys
import concurrent.futures

# Directory Brute Forcer
# Discover hidden directories and files on web servers

def check_path(url, path):
    target = f'{url.rstrip("/")}/{path}'
    try:
        r = requests.get(target, timeout=5, allow_redirects=False)
        if r.status_code not in [404, 403]:
            return (target, r.status_code, len(r.content))
    except:
        pass
    return None

def brute_force(url, wordlist='common.txt'):
    print(f'[*] Brute forcing: {url}\n')

    common_paths = [
        'admin','login','dashboard','api','backup',
        'config','database','db','debug','dev',
        'docs','download','files','images','include',
        'js','css','lib','log','logs','panel',
        'phpmyadmin','private','robots.txt','server-status',
        'sitemap.xml','test','tmp','upload','uploads',
        'wp-admin','wp-login.php','.git','.env',
        '.htaccess','web.config','crossdomain.xml'
    ]

    try:
        with open(wordlist) as f:
            paths = [l.strip() for l in f if l.strip()]
    except FileNotFoundError:
        paths = common_paths

    found = []
    with concurrent.futures.ThreadPoolExecutor(max_workers=10) as ex:
        futures = {ex.submit(check_path, url, p): p for p in paths}
        for f in concurrent.futures.as_completed(futures):
            result = f.result()
            if result:
                found.append(result)
                print(f'  [{result[1]}] {result[0]} ({result[2]} bytes)')

    print(f'\n[*] Found {len(found)} paths')

if __name__ == '__main__':
    url = sys.argv[1] if len(sys.argv) > 1 else 'http://localhost'
    brute_force(url)

