# Multi-threaded Port Scanner
# Fast TCP port scanning with banner grabbing

common_ports = {
    21:'FTP', 22:'SSH', 23:'Telnet', 25:'SMTP',
    53:'DNS', 80:'HTTP', 110:'POP3', 111:'RPCbind',
    135:'MSRPC', 139:'NetBIOS', 143:'IMAP', 443:'HTTPS',
    445:'SMB', 993:'IMAPS', 995:'POP3S', 1723:'PPTP',
    3306:'MySQL', 3389:'RDP', 5432:'PostgreSQL',
    5900:'VNC', 8080:'HTTP-Alt', 8443:'HTTPS-Alt',
    27017:'MongoDB', 6379:'Redis', 11211:'Memcached',
}

def scan_port(target, port, timeout=1):
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(timeout)
        result = sock.connect_ex((target, port))
        if result == 0:
            banner = ''
            try:
                sock.send(b'\r\n')
                banner = sock.recv(1024).decode('utf-8','ignore').strip()[:50]
            except: pass
            sock.close()
            return (port, True, banner)
        sock.close()
    except: pass
    return (port, False, '')

def scan(target, port_range='1-1024'):
    print(f'[*] Scanning {target}\n')

    if '-' in port_range:
        start, end = map(int, port_range.split('-'))
        ports = range(start, end + 1)
    else:
        ports = common_ports.keys()

    open_ports = []
    with concurrent.futures.ThreadPoolExecutor(max_workers=100) as ex:
        futures = {ex.submit(scan_port, target, p): p for p in ports}
        for f in concurrent.futures.as_completed(futures):
            port, is_open, banner = f.result()
            if is_open:
                service = common_ports.get(port, 'unknown')
                open_ports.append(port)
                print(f'  [+] {port:>5}/tcp  open  {service:<15} {banner}')

    print(f'\n[*] {len(open_ports)} open ports found')

if __name__ == '__main__':
    target = sys.argv[1] if len(sys.argv) > 1 else '127.0.0.1'
    scan(target)

