# Subdomain Takeover Checker
# Check CNAME records for vulnerable services

fingerprints = {
    'github.io': 'There isn\'t a GitHub Pages site here',
    'herokuapp.com': 'No such app',
    'pantheon.io': '404 error unknown site',
    'amazonaws.com': 'NoSuchBucket',
    'cloudfront.net': 'Bad request',
    'azure': 'NXDOMAIN',
    'zendesk.com': 'Help Center Closed',
    'shopify.com': 'Sorry, this shop is currently unavailable',
    'fastly.net': 'Fastly error: unknown domain',
    'ghost.io': 'The thing you were looking for is no longer here',
    'surge.sh': 'project not found',
    'bitbucket.io': 'Repository not found',
}

def check_takeover(subdomains):
    print(f'[*] Checking {len(subdomains)} subdomains for takeover\n')

    for sub in subdomains:
        try:
            # Check CNAME
            import subprocess
            result = subprocess.run(['nslookup', '-type=CNAME', sub],
                                  capture_output=True, text=True, timeout=5)
            output = result.stdout

            for service, fingerprint in fingerprints.items():
                if service in output.lower():
                    try:
                        r = requests.get(f'http://{sub}', timeout=5)
                        if fingerprint.lower() in r.text.lower():
                            print(f'  [!] VULNERABLE: {sub} -> {service}')
                            break
                    except:
                        print(f'  [?] POSSIBLE: {sub} -> {service} (connection failed)')
            else:
                print(f'  [OK] {sub}')
        except Exception as e:
            print(f'  [!] Error: {sub} - {e}')

if __name__ == '__main__':
    if len(sys.argv) > 1:
        with open(sys.argv[1]) as f:
            subs = [l.strip() for l in f if l.strip()]
        check_takeover(subs)
    else:
        print('Usage: python takeover_checker.py subdomains.txt')
